import{a as f}from"./chunk-6CBGHGLF.js";import{a as y}from"./chunk-FJZH5UAD.js";import"./chunk-C5F3E4VL.js";import{a as g}from"./chunk-S24A6GUQ.js";import{e as u,f as m}from"./chunk-GSRT3Z5B.js";import{a as h}from"./chunk-GI3WK7PR.js";import{H as a,I as t,J as n,K as i,U as d,d as s,la as p,x as l,y as c}from"./chunk-SLAWZ32U.js";var w=class o{crumbs=[{name:"Home",path:"/"},{name:"FAQ",path:"/faq"}];faqs=[{q:"What is Bible-based Christian counseling, and how is faith integrated?",a:"It is licensed psychotherapy that integrates your faith with evidence-based clinical care. Scripture and prayer are woven in only at your pace and invitation \u2014 never imposed. You receive sound clinical treatment and faith support together, not one instead of the other."},{q:"Do I have to be a Christian to work with you?",a:"Not at all. People of every background are warmly welcome. Faith is integrated only to the degree you want it; your goals always lead the work."},{q:"What is detransition support, and is it \u201Cconversion therapy\u201D?",a:"No \u2014 it is not conversion therapy. Detransition and transition-regret support is voluntary, client-led, trauma-informed talk therapy for adults who have themselves chosen to explore detransition or who are experiencing regret. It follows your goals and never pressures you toward any predetermined outcome."},{q:"How does online therapy in Illinois work, and is it confidential?",a:"Sessions are held over a secure, private telehealth connection with anyone located in Illinois. Therapy is confidential within the standard legal and ethical limits, which I explain clearly at the start."},{q:"What are your fees, and do you accept insurance?",a:"Individual sessions are $130 and couples sessions are $160, with a sliding scale available. More than 30 insurance plans are accepted, including Aetna, BCBS, Cigna, Humana, Medicare, UnitedHealthcare, and TRICARE."},{q:"What concerns do you treat, and who do you see?",a:"I work with adults \u2014 individuals, couples, families, and groups \u2014 on trauma, addiction, abuse recovery, anxiety, depression, grief, relationships, sexual addiction, eating disorders, codependency, and identity concerns from a Bible-based perspective."},{q:"How do I get started, and what happens in the first session?",a:"Reach out by email or the contact page and we\u2019ll arrange a brief, no-pressure conversation. In your first full session we\u2019ll talk through your story and goals at your pace \u2014 there\u2019s no need to know exactly what to say."}];constructor(){s(h).page({title:"Christian Therapy FAQ | Online Illinois | Mason Kelly LCSW",description:"Answers on faith-based therapy, telehealth in Illinois, insurance, detransition support, fees & confidentiality. Get clarity before you book with Mason Kelly LCSW.",path:"/faq"},[m(this.crumbs),u(this.faqs)])}static \u0275fac=function(e){return new(e||o)};static \u0275cmp=c({type:o,selectors:[["app-faq"]],decls:7,vars:2,consts:[["eyebrow","FAQ","heading","Frequently Asked Questions About Online Christian Therapy","lead","Answers to common questions about faith-based therapy, telehealth in Illinois, insurance, and getting started.",3,"crumbs"],["routerLink","/contact",1,"btn","btn--primary"],[1,"section"],[1,"container","container-narrow"],[3,"items"]],template:function(e,r){e&1&&(t(0,"app-page-hero",0)(1,"a",1),d(2,"Still have questions? Reach out"),n()(),t(3,"section",2)(4,"div",3),i(5,"app-faq-list",4),n()(),i(6,"app-cta-banner")),e&2&&(a("crumbs",r.crumbs),l(5),a("items",r.faqs))},dependencies:[p,y,f,g],encapsulation:2})};export{w as FaqPage};
